document.addEventListener("DOMContentLoaded", function () {
  gsap.set("nav", { y: -150 });
  const digit1 = document.querySelector(".digit-1");
  const digit2 = document.querySelector(".digit-2");
  const digit3 = document.querySelector(".digit-3");

  function splitTextIntoSpans(selector) {
    var element = document.querySelector(selector);
    if (element) {
      var text = element.innerText;
      var splitText = text
        .split("")
        .map((char) => `<span>${char}</span>`)
        .join("");
      element.innerHTML = splitText;
    }
  }

  splitTextIntoSpans(".header h1");

  for (let i = 0; i < 2; i++) {
    for (let j = 0; j < 10; j++) {
      const div = document.createElement("div");
      div.className = "num";
      div.textContent = j;
      digit3.appendChild(div);
    }
  }

  const finalDigit = document.createElement("div");
  finalDigit.className = "num";
  finalDigit.textContent = "0";
  digit3.appendChild(finalDigit);

  function animate(digit, duration, delay = 1) {
    const numHeight = digit.querySelector(".num").clientHeight;
    const totalDistance =
      (digit.querySelectorAll(".num").length - 1) * numHeight;
    gsap.to(digit, {
      y: -totalDistance,
      duration: duration,
      delay: delay,
      ease: "power2.inOut",
    });
  }

  animate(digit3, 5);
  animate(digit2, 6);
  animate(digit1, 2, 5);

  gsap.to(".progress-bar", {
    width: "30%",
    duration: 2,
    ease: "power4.inOut",
    delay: 7,
  });

  gsap.to(".progress-bar", {
    width: "100%",
    opacity: 0,
    duration: 2,
    delay: 8.5,
    ease: "power3.out",
    onComplete: () => {
      gsap.set(".pre-loader", {
        display: "none",
      });
    },
  });

  gsap.to(".hero-imgs > img", {
    clipPath: "polygon(100% 0%, 0% 0%, 0% 100%, 100% 100%)",
    duration: 1,
    ease: "power4.inOut",
    stagger: 0.25,
    delay: 9,
  });

  gsap.to(".hero", {
    scale: 1.3,
    duration: 3,
    ease: "power3.inOut",
    delay: 9,
  });

  gsap.to("nav", {
    y: 0,
    duration: 1,
    ease: "power3.out",
    delay: 11,
  });

  gsap.to("h1 span", {
    top: "0px",
    stagger: 0.1,
    duration: 1,
    ease: "power3.out",
    delay: 11,
  });
});

code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100vw;
  height: 100vh;
  overflow: hidden;
  background: #ebdc0b;
}

img {
  position: absolute;
  width: 100%;
  height: 100%;
  object-fit: cover;
  clip-path: polygon(100% 0%, 100% 0%, 100% 100%, 100% 100%);
}

.hero {
  width: 100vw;
  height: 100vh;
  padding: 3em;
}

.pre-loader {
  width: 200%;
  height: 100%;
  padding: 2em;
  position: fixed;
  top: 0;
  right: 0;
  display: flex;
  justify-content: flex-end;
  align-items: flex-end;
  gap: 0.5em;
  overflow: hidden;
  z-index: 2;
}

.pre-loader p {
  width: max-content;
  text-transform: uppercase;
  font-family: "Timmons NY";
  font-size: 60px;
  line-height: 60px;
}

.counter {
  height: 100px;
  display: flex;
  font-family: "Timmons NY";
  font-size: 100px;
  font-weight: 400;
  line-height: 150px;
  clip-path: polygon(0 0, 100% 0, 100% 100px, 0 100px);
}

.digit-1,
.digit-2,
.digit-3,
.digit-4 {
  position: relative;
  top: -15px;
}

.offset {
  position: relative;
  right: -7.5px;
}

.progress-bar {
  position: relative;
  top: -15px;
  width: 0%;
  height: 4px;
  background: #000;
}

.hero-imgs {
  position: relative;
  width: 100%;
  height: 100%;
  overflow: hidden;
  z-index: 0;
}

.website-content {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  z-index: 1;
}

nav {
  position: fixed;
  top: 0;
  width: 100%;
  display: flex;
  padding: 2em;
}

nav > div {
  flex: 1;
  font-family: "Timmons NY";
  font-size: 36px;
  font-weight: lighter;
  color: #ebdc0b;
  text-transform: uppercase;
}

.site-info {
  text-align: center;
}

.menu {
  text-align: right;
}

.header {
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
}

h1 {
  text-transform: uppercase;
  font-family: "PP Neue World";
  font-size: 20vw;
  font-weight: 200;
  color: #ebdc0b;
  clip-path: polygon(0 0, 100% 0, 100% 100%, 0 100%);
}

h1 span {
  position: relative;
  top: 400px;
}

@media (max-width: 900px) {
  .pre-loader {
    padding: 1em;
    gap: 0.5em;
  }

  .counter {
    font-size: 70px;
  }

  .pre-loader p {
    font-size: 40px;
    line-height: 64px;
  }

  .offset {
    position: relative;
    right: -5px;
  }
}
